import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface Milestone {
  title: string;
  dueDate: string;
  progress: number;
  description: string;
}

interface Deadline {
  task: string;
  dueDate: string;
}

interface ProgressPoint {
  date: string;
  progress: number;
}

interface WidgetData {
  currentMilestone: Milestone;
  upcomingDeadlines: Deadline[];
  timelineProgress: ProgressPoint[];
}

export default function Widget() {
  const data = response.data as WidgetData;
  const { currentMilestone, upcomingDeadlines, timelineProgress } = data;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              {currentMilestone.title}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Due Date: {new Date(currentMilestone.dueDate).toLocaleDateString()}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {currentMilestone.description}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              Upcoming Deadlines
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {upcomingDeadlines.map((deadline, index) => (
                <Chip
                  key={index}
                  label={`${deadline.task} (${new Date(deadline.dueDate).toLocaleDateString()})`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5 }}
                />
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 120 }}>
            <LineChart
              series={[
                {
                  data: timelineProgress.map(point => point.progress),
                  color: '#FF5722',
                  curve: 'linear',
                  showMark: false,
                },
              ]}
              xAxis={[
                {
                  data: timelineProgress.map(point => point.date),
                  hide: true,
                },
              ]}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
              sx={{
                '& .MuiLineElement-root': {
                  strokeWidth: 2,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
